use varg_os_types::*;
use varg_runtime::*;

fn is_even(n: i64) -> bool {
    return n % 2 == 0;
}

fn square(n: i64) -> i64 {
    return n * n;
}

struct DataPipeline {
    pub total: i64,
}

impl DataPipeline {
    pub fn new() -> Self {
        let mut __self = DataPipeline {
            total: 0,
        };
        __self.Init();
        __self
    }
    pub fn Init(&mut self) {
        self.total = 0;
    }
    pub fn Run(&mut self) {
        let mut data = vec![0];
        let mut idx = 1;
        while idx < 10000 {
            data.push(idx);
            idx += 1;
        }
        let mut sum = 0;
        let mut fi = 0;
        while fi < 10000 {
            let mut val = data[fi as usize];
            if is_even(val.clone()) {
                sum += square(val.clone());
            }
            fi += 1;
        }
        self.total = sum;
        let mut csv = "id,value,squared\\n".to_string();
        let mut ci = 0;
        while ci < 100 {
            let mut sq = square(ci.clone());
            csv += format!("{},{},{}\n", ci, ci * 2, sq);
            ci += 1;
        }
        println!("{:?}", format!("Sum of squared evens: {}", self.total));
        println!("{:?}", format!("CSV length: {}", csv.length()));
    }
}

